#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char* join_strings(const char* a, const char* b) {
    char* res = malloc(strlen(a) + strlen(b) + 1);
    strcpy(res, a);
    strcat(res, b);
    return res;
}

